fun solve(nums: Array<Long>, k: Long): Long {
    val sorted = nums.sorted()
    val n = sorted.size
    if (n == 0) return 0L
    var maxLength = 1
    for (i in 0 until n) {
        val target = sorted[i] * k
        val subList = sorted.subList(i, n)
        val upperBoundIndex = subList.upperBound(target)
        val currentLength = upperBoundIndex
        if (currentLength > maxLength) {
            maxLength = currentLength
        }
    }
    return n.toLong() - maxLength
}
```

